body.script:
test(function() {
  assert_background_color('t1', LIME, "t1 should be green");
  assert_background_color('t2', LIME, "t2 should be green");
  assert_background_color('t3', LIME, "t3 should be green");
  assert_not_background_color('t4', RED, "t4 should not be red");
  assert_not_background_color('t5', RED, "t5 should not be red");
}, 'Universal selector with declared namespace');
